// src/client.ts
import { Client, IntentsBitField, Partials } from "discord.js";
import { styleText } from "node:util";
import { ConstaticApp } from "./app.js";
var defaultIntents = Object.values(IntentsBitField.Flags).filter((t) => typeof t !== "string");
var defaultPartials = Object.values(Partials).filter((t) => typeof t !== "string");
function createClient(token, options) {
  const app = ConstaticApp.getInstance();
  const client = new Client({
    ...options,
    intents: options.intents ?? defaultIntents,
    partials: options.partials ?? defaultPartials,
    failIfNotExists: options.failIfNotExists ?? false
  });
  client.token = token;
  client.once("clientReady", async (client2) => {
    console.log("%s %s %s", styleText("green", "●"), styleText(["greenBright", "underline"], client2.user.username), styleText("green", "application is ready!"));
    await app.commands.register(client2);
    await app.events.runReady(client2);
  });
  client.on("interactionCreate", async (interaction) => {
    if (interaction.isAutocomplete()) {
      await app.commands.onAutocomplete(interaction);
      return;
    }
    if (interaction.isCommand()) {
      await app.commands.onCommand(interaction);
      return;
    }
    await app.responders.onResponder(interaction);
  });
  return client;
}
export {
  createClient
};
